const data = $input.first().json;
const chatId = $('Expresiones regulares').first().json.chatId;

let mensaje = '🏢 *NullTrace — Búsqueda de Negocio*\n\n';
mensaje += `🔍 *Búsqueda:* ${data.nombre}\n\n`;

if (data.total <= 1) {
  mensaje += '❌ No se encontraron negocios con ese nombre.';
} else {
  const empresas = data.resultados.filter(r => 
    !r.startsWith('Ver información') && 
    !r.startsWith('Cerca de') &&
    r.length > 50
  );

  mensaje += `📋 *${empresas.length} negocio(s) encontrado(s):*\n\n`;

  empresas.forEach((empresa, i) => {
    const lineas = empresa.split('\n').filter(l => l.trim());
    const nombre = lineas[0];

    const camaraMatch = empresa.match(/Cámara de Comercio\s*\n\s*(.+)/);
    const estadoMatch = empresa.match(/Estado\s*\n\s*(.+)/);
    const matriculaMatch = empresa.match(/Número de Matrícula\s*\n\s*(.+)/);

    const camara = camaraMatch ? camaraMatch[1].trim() : '';
    const estado = estadoMatch ? estadoMatch[1].trim() : '';
    const matricula = matriculaMatch ? matriculaMatch[1].trim() : '';

    mensaje += `*${i+1}. ${nombre}*\n`;
    mensaje += `📍 *Ciudad:* ${camara}\n`;
    mensaje += `🔢 *Matrícula:* ${matricula}\n`;
    mensaje += `📌 *Estado:* ${estado}\n\n`;
  });
}

return [{ json: { mensaje, chatId } }];

const data = $input.first().json;
const chatId = $('Expresiones regulares').first().json.chatId;
const placa = $('Expresiones regulares').first().json.texto;

const simitFallo = !data || data.error || data.totalGeneral === undefined;

if (simitFallo) {
  return [{ json: { mensaje: "👁️ *NULLTRACE // PLACA*\n━━━━━━━━━━━━━━━━━━\n\n🎯 *OBJETIVO:* `" + placa + "`\n\n🚦 *SIMIT — ESTADO DE CUENTA*\n─────────────────────\n⚠️ *SIMIT:* Portal no disponible en este momento.\n🔄 Intenta de nuevo en unos minutos.\n\n━━━━━━━━━━━━━━━━━━\n🔍 _NullTrace OSINT Bot_", chatId } }];
}

const estaPazSalvo = data.pazSalvo || data.totalGeneral === 0;
const multas = Array.isArray(data.multas) ? data.multas : [];
const comparendos = Array.isArray(data.comparendos) ? data.comparendos : [];
const cursos = Array.isArray(data.cursos) ? data.cursos : [];
const acuerdos = Array.isArray(data.acuerdosPago) ? data.acuerdosPago : [];

let mensaje = "👁️ *NULLTRACE // PLACA*\n";
mensaje += "━━━━━━━━━━━━━━━━━━\n\n";
mensaje += "🎯 *OBJETIVO:* `" + placa + "`\n\n";
mensaje += "🚦 *SIMIT — ESTADO DE CUENTA*\n";
mensaje += "─────────────────────\n";
mensaje += (estaPazSalvo ? "✅ *PAZ Y SALVO:* SÍ\n" : "❌ *PAZ Y SALVO:* NO\n");
mensaje += "💰 *TOTAL A PAGAR:* $" + (data.totalGeneral || 0).toLocaleString() + "\n";

if (comparendos.length === 0 && multas.length === 0) {
  mensaje += "\n✅ Sin comparendos ni multas activas\n";
}

const formatarRegistro = (r, i, tipo) => {
  const nombreRaw = r.infractor ? (r.infractor.nombre + ' ' + r.infractor.apellido) : 'N/A';
  const nombre = nombreRaw.replace(/\*/g, '').trim();
  const doc = r.infractor ? r.infractor.numeroDocumento : 'N/A';
  const placa = r.placa || 'N/A';
  const fechaComp = r.fechaComparendo || 'N/A';
  const fechaRes = r.fechaResolucion || 'N/A';
  const ubicacion = (r.organismoTransito || 'N/A') + ' — ' + (r.departamento || 'N/A');
  const estadoCartera = r.estadoCartera || 'N/A';
  const nroCoactivo = r.nroCoactivo || 'N/A';
  const valor = (r.valor || 0).toLocaleString();
  const intereses = Math.round(r.valorIntereses || 0).toLocaleString();
  const total = (r.valorPagar || 0).toLocaleString();
  const nroComparendo = r.numeroComparendo || 'N/A';
  const codInfraccion = (r.infracciones && r.infracciones[0]) ? r.infracciones[0].codigoInfraccion : 'N/A';
  const descInfraccion = (r.infracciones && r.infracciones[0]) ? r.infracciones[0].descripcionInfraccion : 'N/A';

  let bloque = "\n" + tipo + " *" + (i+1) + ". #" + nroComparendo + "*\n";
  bloque += "🚗 *PLACA:* " + placa + "\n";
  bloque += "👤 *INFRACTOR:* " + nombre + "\n";
  bloque += "🪪 *DOCUMENTO:* " + doc + "\n";
  bloque += "📅 *FECHA COMPARENDO:* " + fechaComp + "\n";
  bloque += "📋 *FECHA RESOLUCIÓN:* " + fechaRes + "\n";
  bloque += "📍 *UBICACIÓN:* " + ubicacion + "\n";
  bloque += "⚖️ *ESTADO CARTERA:* " + estadoCartera + "\n";
  bloque += "🔴 *NRO COACTIVO:* " + nroCoactivo + "\n";
  bloque += "💵 *MULTA:* $" + valor + "\n";
  bloque += "📈 *INTERESES:* $" + intereses + "\n";
  bloque += "💰 *TOTAL:* $" + total + "\n";
  bloque += "📌 *INFRACCIÓN:* " + codInfraccion + ": _" + descInfraccion + "_\n";
  return bloque;
};

if (comparendos.length > 0) {
  mensaje += "\n🚨 *COMPARENDOS (" + comparendos.length + ")*\n";
  comparendos.forEach((c, i) => { mensaje += formatarRegistro(c, i, '🚨'); });
}

if (multas.length > 0) {
  mensaje += "\n⚠️ *MULTAS (" + multas.length + ")*\n";
  multas.forEach((m, i) => { mensaje += formatarRegistro(m, i, '⚠️'); });
}

if (cursos.length > 0) {
  mensaje += "\n📚 *CURSOS PENDIENTES:* " + cursos.length + "\n";
}

if (acuerdos.length > 0) {
  mensaje += "🤝 *ACUERDOS DE PAGO:* " + acuerdos.length + "\n";
}

mensaje += "\n━━━━━━━━━━━━━━━━━━\n";
mensaje += "🔍 _NullTrace OSINT Bot_";

return [{ json: { mensaje, chatId } }];

const ruesData = $('ConsultaRues').first().json;
const simitRaw = $('Consulta simit').first().json;
const cedula = $('Expresiones regulares').first().json.texto;
const chatId = $('Expresiones regulares').first().json.chatId;

// Detectar si el SIMIT falló completamente (Continue on fail manda {error, message})
const simitFallo = !simitRaw || simitRaw.error !== undefined || simitRaw.totalGeneral === undefined;
const ruesFallo = !ruesData || !ruesData.resultados || ruesData.total === 0;

if (simitFallo && ruesFallo) {
  return [{ json: { mensaje: "👁️ *NULLTRACE // CÉDULA*\n━━━━━━━━━━━━━━━━━━\n\n🎯 *OBJETIVO:* `" + cedula + "`\n\n⚠️ No se pudo obtener información. Intenta de nuevo en unos minutos.\n\n━━━━━━━━━━━━━━━━━━\n🔍 _NullTrace OSINT Bot_", chatId } }];
}

// --- Parsear RUES ---
let nombrePersona = null;
let categoria = 'No disponible';
let camara = 'No disponible';
let estadoPersona = 'No disponible';
let negocios = [];
let ruesEncontró = false;

if (!ruesFallo) {
  const textoRues = ruesData.resultados[0] || '';
  const noEncontrado = textoRues.startsWith('No se encontraron resultados');
  if (!noEncontrado) {
    const empresas = ruesData.resultados.filter(r =>
      !r.startsWith('Ver información') &&
      !r.startsWith('Cerca de') &&
      !r.startsWith('No se encontraron') &&
      r.length > 50
