      const camaraMatch = primera.match(/Cámara de Comercio\s*\n\s*(.+)/);
      const estadoMatch = primera.match(/Estado\s*\n\s*(.+)/);
      const categoriaMatch = primera.match(/Categoria\s*\n\s*(.+)/);
      camara = camaraMatch ? camaraMatch[1].trim() : 'No disponible';
      estadoPersona = estadoMatch ? estadoMatch[1].trim() : 'No disponible';
      categoria = categoriaMatch ? categoriaMatch[1].trim() : 'No disponible';
      empresas.slice(1).forEach(empresa => {
        const lineasNeg = empresa.split('\n').filter(l => l.trim());
        const nombreNeg = lineasNeg[0];
        const estadoNegMatch = empresa.match(/Estado\s*\n\s*(.+)/);
        const estadoNeg = estadoNegMatch ? estadoNegMatch[1].trim() : '';
        const emoji = estadoNeg === 'Activa' ? '🟢' : '🔴';
        negocios.push(emoji + ' ' + nombreNeg + ' | ' + estadoNeg);
      });
    }
  }
}

const infoNegocios = negocios.length > 0 ? negocios.join('\n') : '∅  Sin negocios registrados';

// --- Mensaje ---
let mensaje = "👁️ *NULLTRACE // CÉDULA*\n";
mensaje += "━━━━━━━━━━━━━━━━━━\n\n";
mensaje += "🎯 *OBJETIVO:* `" + cedula + "`\n\n";

mensaje += "📡 *REGISTRO MERCANTIL — RUES*\n";
mensaje += "─────────────────────\n";
if (ruesEncontró && nombrePersona) {
  mensaje += "👤 *NOMBRE:* " + nombrePersona.replace(/\*/g, '').trim() + "\n";
  mensaje += "📋 *CATEGORÍA:* " + categoria + "\n";
  mensaje += "🏛️ *CÁMARA:* " + camara + "\n";
  mensaje += "📌 *ESTADO:* " + estadoPersona + "\n";
  if (negocios.length > 0) {
    mensaje += "\n🏢 *NEGOCIOS REGISTRADOS*\n" + infoNegocios + "\n";
  } else {
    mensaje += "🏢 *NEGOCIOS:* Sin negocios registrados\n";
  }
} else {
  mensaje += "∅  Sin registro mercantil encontrado\n";
}

mensaje += "\n🚦 *SIMIT — ESTADO DE CUENTA*\n";
mensaje += "─────────────────────\n";

if (simitFallo) {
  mensaje += "⚠️ *SIMIT:* Portal no disponible en este momento.\n";
  mensaje += "🔄 Intenta de nuevo en unos minutos o consulta la placa directamente.\n";
} else {
  const estaPazSalvo = simitRaw.pazSalvo && simitRaw.totalGeneral === 0;
  mensaje += (estaPazSalvo ? "✅ *PAZ Y SALVO:* SÍ\n" : "❌ *PAZ Y SALVO:* NO\n");
  mensaje += "💰 *TOTAL A PAGAR:* $" + (simitRaw.totalGeneral || 0).toLocaleString() + "\n";

  const multas = Array.isArray(simitRaw.multas) ? simitRaw.multas : [];
  const comparendos = Array.isArray(simitRaw.comparendos) ? simitRaw.comparendos : [];

  if (comparendos.length === 0 && multas.length === 0) {
    mensaje += "\n✅ Sin comparendos ni multas activas\n";
  }

  const formatarRegistro = (r, i, tipo) => {
    const nombreRaw = r.infractor ? (r.infractor.nombre + ' ' + r.infractor.apellido) : 'N/A';
    const nombre = nombreRaw.replace(/\*/g, '').trim();
    const doc = r.infractor ? r.infractor.numeroDocumento : 'N/A';
    const placa = r.placa || 'N/A';
    const fechaComp = r.fechaComparendo || 'N/A';
    const fechaRes = r.fechaResolucion || 'N/A';
    const ubicacion = (r.organismoTransito || 'N/A') + ' — ' + (r.departamento || 'N/A');
    const estadoCartera = r.estadoCartera || 'N/A';
    const nroCoactivo = r.nroCoactivo || 'N/A';
    const valor = (r.valor || 0).toLocaleString();
    const intereses = Math.round(r.valorIntereses || 0).toLocaleString();
    const total = (r.valorPagar || 0).toLocaleString();
    const nroComparendo = r.numeroComparendo || 'N/A';
    const codInfraccion = (r.infracciones && r.infracciones[0]) ? r.infracciones[0].codigoInfraccion : 'N/A';
    const descInfraccion = (r.infracciones && r.infracciones[0]) ? r.infracciones[0].descripcionInfraccion : 'N/A';

    let bloque = "\n" + tipo + " *" + (i+1) + ". #" + nroComparendo + "*\n";
    bloque += "🚗 *PLACA:* " + placa + "\n";
    bloque += "👤 *INFRACTOR:* " + nombre + "\n";
    bloque += "🪪 *DOCUMENTO:* " + doc + "\n";
    bloque += "📅 *FECHA COMPARENDO:* " + fechaComp + "\n";
    bloque += "📋 *FECHA RESOLUCIÓN:* " + fechaRes + "\n";
    bloque += "📍 *UBICACIÓN:* " + ubicacion + "\n";
    bloque += "⚖️ *ESTADO CARTERA:* " + estadoCartera + "\n";
    bloque += "🔴 *NRO COACTIVO:* " + nroCoactivo + "\n";
    bloque += "💵 *MULTA:* $" + valor + "\n";
    bloque += "📈 *INTERESES:* $" + intereses + "\n";
    bloque += "💰 *TOTAL:* $" + total + "\n";
    bloque += "📌 *INFRACCIÓN:* " + codInfraccion + ": _" + descInfraccion + "_\n";
    return bloque;
  };

  if (comparendos.length > 0) {
    mensaje += "\n🚨 *COMPARENDOS (" + comparendos.length + ")*\n";
    comparendos.forEach((c, i) => { mensaje += formatarRegistro(c, i, '🚨'); });
  }

  if (multas.length > 0) {
    mensaje += "\n⚠️ *MULTAS (" + multas.length + ")*\n";
    multas.forEach((m, i) => { mensaje += formatarRegistro(m, i, '⚠️'); });
  }
}

mensaje += "\n━━━━━━━━━━━━━━━━━━\n";
mensaje += "🔍 _NullTrace OSINT Bot_";

return [{ json: { mensaje, chatId } }];

const mensaje = $input.first().json.message;
const texto = mensaje.text.trim();
const chatId = mensaje.chat.id;

if (texto === '/start') {
  return [{ json: { texto, chatId, tipo: 'start' } }];
}

if (texto.startsWith('/negocio ')) {
  const nombreNegocio = texto.replace('/negocio ', '').trim();
  return [{ json: { texto: nombreNegocio, chatId, tipo: 'negocio' } }];
}

let tipo = '';
let textoLimpio = texto;

if (texto.startsWith('+')) {
  textoLimpio = texto.replace('+57', '').replace('+', '');
  tipo = 'telefono';
} else if (/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(texto)) {
  tipo = 'correo';
} else if (/^[A-Za-z]{3}\d{3}$/.test(texto)) {
  // placa colombiana — 3 letras y 3 números
  tipo = 'placa';
} else if (/^[A-Za-z]{3}\d{2}[A-Za-z]$/.test(texto)) {
  // placa moto colombiana — 3 letras, 2 números, 1 letra
  tipo = 'placa';
} else if (/^3\d{9}$/.test(texto)) {
  tipo = 'telefono';
} else if (/^\d{6,10}$/.test(texto)) {
  tipo = 'cedula';
} else {
  tipo = 'desconocido';
}

// Para correo no aplicar toUpperCase
const textoFinal = tipo === 'correo' ? textoLimpio.toLowerCase() : textoLimpio.toUpperCase();
return [{ json: { texto: textoFinal, chatId, tipo } }];

const data = $input.first().json;
const chatId = $('Expresiones regulares').first().json.chatId;
const correo = $('Expresiones regulares').first().json.texto;

// URLs base conocidas para los sitios más comunes
const urlsConocidas = {
  twitter:    "https://twitter.com/search?q=",
  instagram:  "https://www.instagram.com/",
  github:     "https://github.com/search?q=",
  facebook:   "https://www.facebook.com/search/top?q=",
  spotify:    "https://open.spotify.com/search/",
  patreon:    "https://www.patreon.com/search?q=",
  tumblr:     "https://www.tumblr.com/search/",
  flickr:     "https://www.flickr.com/search/?text=",
  lastfm:     "https://www.last.fm/search?q=",
  pinterest:  "https://www.pinterest.com/search/pins/?q=",
  wordpress:  "https://en.search.wordpress.com/?q=",
  devrant:    "https://devrant.com/search?term=",
  quora:      "https://www.quora.com/search?q=",
  strava:     "https://www.strava.com/athletes/search?text=",
  adobe:      "https://adobe.com",
  zoho:       "https://zoho.com",
  freelancer: "https://www.freelancer.com/search/users/?q=",
  linkedin:   "https://www.linkedin.com/search/results/all/?keywords=",
  vsco:       "https://vsco.co/search/images/",
  issuu:      "https://issuu.com/search#q=",
  xing:       "https://www.xing.com/search/members?q=",
};

const fallo = !data || data.total_encontrados === undefined;

if (fallo) {
  return [{ json: { 
    mensaje: "👁️ *NULLTRACE // EMAIL*\n━━━━━━━━━━━━━━━━━━\n\n🎯 *OBJETIVO:* `" + correo + "`\n\n⚠️ No se pudo consultar. Intenta de nuevo.\n\n━━━━━━━━━━━━━━━━━━\n🔍 _NullTrace OSINT Bot_", 
    chatId 
  }}];
}

const encontrados = data.registrado_en || [];
const rateLimited = data.rate_limited || [];

// Construir lista de plataformas con link de búsqueda si está disponible
let listaPlataformas = '';
if (encontrados.length === 0) {
  listaPlataformas = '∅  No se encontró registro en ninguna plataforma\n';
} else {
  encontrados.forEach(nombre => {
    const baseUrl = urlsConocidas[nombre.toLowerCase()];
    if (baseUrl) {
      const url = baseUrl + encodeURIComponent(correo);
      listaPlataformas += `🔗 [${nombre}](${url})\n`;
    } else {
      listaPlataformas += `✅ ${nombre}\n`;
    }
  });
}

let mensaje = "👁️ *NULLTRACE // EMAIL*\n";
mensaje += "━━━━━━━━━━━━━━━━━━\n\n";
mensaje += "🎯 *OBJETIVO:* `" + correo + "`\n\n";

mensaje += "📡 *PLATAFORMAS DETECTADAS*\n";
mensaje += "─────────────────────\n";
mensaje += "📊 *Consultados:* ~121 sitios\n";
mensaje += "✅ *Registrado en:* " + encontrados.length + " plataformas\n";
mensaje += "⚠️ *Sin respuesta:* " + rateLimited.length + " sitios\n\n";

if (encontrados.length > 0) {
  mensaje += "🌐 *CUENTAS ENCONTRADAS*\n";
  mensaje += listaPlataformas + "\n";
  mensaje += "_⚠️ Los links llevan a búsquedas, no al perfil directo._\n";
}

mensaje += "\n━━━━━━━━━━━━━━━━━━\n";
mensaje += "🔍 _NullTrace OSINT Bot_";

return [{ json: { mensaje, chatId } }];
